class TreeNode:
    def __init__(self, value):
        self.value = value
        self.left = None
        self.right = None


def preorder(root):
    if root is None:
        return []

    result = [root.value]
    result.extend(preorder(root.left))
    result.extend(preorder(root.right))
    return result


def inorder(root):
    if root is None:
        return []

    result = inorder(root.left)
    result.append(root.value)
    result.extend(inorder(root.right))
    return result


def postorder(root):
    if root is None:
        return []

    result = postorder(root.left)
    result.extend(postorder(root.right))
    result.append(root.value)
    return result
